import{_ as i,o as s,c as a,ag as n}from"./chunks/framework.ppPvAPr9.js";const k=JSON.parse('{"title":"你所理解的前端工程化（未整理）","description":"","frontmatter":{},"headers":[],"relativePath":"interview/解决方案/前端工程化/index.md","filePath":"interview/解决方案/前端工程化/index.md"}'),l={name:"interview/解决方案/前端工程化/index.md"};function e(p,t,d,o,r,h){return s(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="你所理解的前端工程化-未整理" tabindex="-1">你所理解的前端工程化（未整理） <a class="header-anchor" href="#你所理解的前端工程化-未整理" aria-label="Permalink to &quot;你所理解的前端工程化（未整理）&quot;">​</a></h1><p>前端工程化是指通过利用各种工具和技术，将前端开发流程进行标准化、自动化和规范化，提高前端开发效率和代码质量。</p><p>前端工程化的主要体现包括以下几个方面：</p><ul><li><p>模块化：前端工程化中的模块化可以通过使用模块化规范（如CommonJS、ES6模块等）或模块打包工具（如Webpack、Rollup等）来实现，以便更好地管理项目中的代码和依赖关系。</p></li><li><p>自动化构建：自动化构建工具（如Gulp、Grunt、Webpack等）可以将前端开发中的各个环节（如编译、压缩、打包、部署等）自动化，提高开发效率和代码质量。</p></li><li><p>代码质量检查：前端工程化中可以使用代码质量检查工具（如ESLint、StyleLint等）来自动检查代码是否符合规范和最佳实践，减少代码错误和风险。</p></li><li><p>自动化测试：自动化测试工具（如Jest、Mocha等）可以自动化执行测试用例，确保代码的正确性和稳定性。 组件化：通过组件化开发，可以将页面分解为多个组件，每个组件具有独立的结构、样式和行为，以便更好地管理和重用代码。</p></li><li><p>版本控制：版本控制工具（如Git、SVN等）可以帮助开发者更好地管理代码版本，协同开发和追踪代码变更历史。</p></li><li><p>文档化：文档化可以通过自动生成API文档、组件文档、代码注释等方式来实现，以便更好地管理和分享项目文档。</p></li></ul><h2 id="q-什么是-ci-cd-在前端项目里通常怎么落地" tabindex="-1">Q: 什么是 CI/CD？在前端项目里通常怎么落地？ <a class="header-anchor" href="#q-什么是-ci-cd-在前端项目里通常怎么落地" aria-label="Permalink to &quot;Q: 什么是 CI/CD？在前端项目里通常怎么落地？&quot;">​</a></h2><p><strong>A:</strong></p><p><strong>CI/CD</strong> 是把代码从提交到上线变成自动化流水线的工程实践。</p><ul><li><strong>CI（持续集成）</strong>：开发者频繁提交代码后，自动执行安装依赖、代码检查、单元测试、构建，尽早发现问题。</li><li><strong>CD（持续交付/持续部署）</strong>：在 CI 通过后，自动将构建产物发布到测试环境或生产环境。</li></ul><p><strong>前端常见流水线阶段：</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">stages</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">:</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">	-</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> install</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">	-</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> lint</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">	-</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> test</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">	-</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> build</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">	-</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> deploy</span></span></code></pre></div><table tabindex="0"><thead><tr><th>维度</th><th>持续交付（Continuous Delivery）</th><th>持续部署（Continuous Deployment）</th></tr></thead><tbody><tr><td>发布触发</td><td>人工确认后发布</td><td>流水线通过即自动发布</td></tr><tr><td>风险控制</td><td>✅ 可控性更高</td><td>❌ 对测试和回滚能力要求更高</td></tr><tr><td>适用场景</td><td>业务变更频繁但需人工把关</td><td>自动化能力成熟、发布节奏快</td></tr></tbody></table><p><strong>前端项目落地要点：</strong></p><ul><li>按分支策略区分环境：如 <code>main</code> 对应生产，<code>develop</code> 对应测试。</li><li>构建产物统一管理：上传到对象存储或制品仓库，保证可追溯。</li><li>部署前后加入质量门禁：如 Lighthouse 指标阈值、E2E 冒烟测试。</li><li>提供快速回滚：基于版本号或 commit hash 一键回退。</li></ul><blockquote><p>⚠️ <strong>注意</strong>：前端 CI/CD 不只是“自动打包上传”，还应包含质量门禁、灰度发布和回滚策略，否则只是半自动发布脚本。</p></blockquote><hr>`,15)])])}const g=i(l,[["render",e]]);export{k as __pageData,g as default};
